import { calculateDelayWithJitter, calculateExponentialDelay, isRetryableError, sleep, withRetry, BraveApiError, } from './retry.js';
import { RETRY_CONFIG } from '../constants.js';
import { vi, describe, it, expect, beforeEach } from 'vitest';
// Mock console methods to avoid cluttering test output
global.console.info = vi.fn();
global.console.warn = vi.fn();
global.console.error = vi.fn();
describe('calculateDelayWithJitter', () => {
    it('should return a delay between 0 and baseDelay', () => {
        const baseDelay = 1000;
        const delays = Array.from({ length: 100 }, () => calculateDelayWithJitter(baseDelay));
        delays.forEach((delay) => {
            expect(delay).toBeGreaterThanOrEqual(0);
            expect(delay).toBeLessThanOrEqual(baseDelay);
        });
    });
    it('should return different values on multiple calls (randomness)', () => {
        const baseDelay = 1000;
        const delays = Array.from({ length: 10 }, () => calculateDelayWithJitter(baseDelay));
        const uniqueDelays = new Set(delays);
        // With randomness, we should get some different values
        expect(uniqueDelays.size).toBeGreaterThan(1);
    });
    it('should handle zero baseDelay', () => {
        const delay = calculateDelayWithJitter(0);
        expect(delay).toBe(0);
    });
});
describe('calculateExponentialDelay', () => {
    it('should calculate exponential backoff correctly', () => {
        const baseDelay = 1000;
        const maxDelay = 30000;
        const multiplier = 2;
        expect(calculateExponentialDelay(0, baseDelay, maxDelay, multiplier)).toBe(1000);
        expect(calculateExponentialDelay(1, baseDelay, maxDelay, multiplier)).toBe(2000);
        expect(calculateExponentialDelay(2, baseDelay, maxDelay, multiplier)).toBe(4000);
        expect(calculateExponentialDelay(3, baseDelay, maxDelay, multiplier)).toBe(8000);
        expect(calculateExponentialDelay(4, baseDelay, maxDelay, multiplier)).toBe(16000);
    });
    it('should cap delay at maxDelay', () => {
        const baseDelay = 1000;
        const maxDelay = 10000;
        const multiplier = 2;
        // Without capping: 1000 * 2^5 = 32000
        // With capping: 10000
        expect(calculateExponentialDelay(5, baseDelay, maxDelay, multiplier)).toBe(10000);
        expect(calculateExponentialDelay(10, baseDelay, maxDelay, multiplier)).toBe(10000);
    });
    it('should handle zero attempt', () => {
        const delay = calculateExponentialDelay(0, 1000, 30000, 2);
        expect(delay).toBe(1000);
    });
});
describe('isRetryableError', () => {
    it('should return true for retryable status codes', () => {
        const retryableCodes = RETRY_CONFIG.RETRYABLE_STATUS_CODES;
        retryableCodes.forEach((statusCode) => {
            const error = new BraveApiError(statusCode);
            expect(isRetryableError(error, retryableCodes)).toBe(true);
        });
    });
    it('should return false for non-retryable status codes', () => {
        const nonRetryableCodes = [400, 401, 403, 404, 422];
        const retryableCodes = RETRY_CONFIG.RETRYABLE_STATUS_CODES;
        nonRetryableCodes.forEach((statusCode) => {
            const error = new BraveApiError(statusCode);
            expect(isRetryableError(error, retryableCodes)).toBe(false);
        });
    });
    it('should return true for network errors (TypeError)', () => {
        const networkError = new TypeError('fetch failed');
        expect(isRetryableError(networkError, RETRY_CONFIG.RETRYABLE_STATUS_CODES)).toBe(true);
    });
    it('should return true for ECONNRESET errors', () => {
        const error = new TypeError('ECONNRESET');
        expect(isRetryableError(error, RETRY_CONFIG.RETRYABLE_STATUS_CODES)).toBe(true);
    });
    it('should return true for ETIMEDOUT errors', () => {
        const error = new TypeError('ETIMEDOUT');
        expect(isRetryableError(error, RETRY_CONFIG.RETRYABLE_STATUS_CODES)).toBe(true);
    });
    it('should return false for other error types', () => {
        const error = new Error('Some other error');
        expect(isRetryableError(error, RETRY_CONFIG.RETRYABLE_STATUS_CODES)).toBe(false);
    });
    it('should return false for non-Error objects', () => {
        expect(isRetryableError('string error', RETRY_CONFIG.RETRYABLE_STATUS_CODES)).toBe(false);
        expect(isRetryableError(null, RETRY_CONFIG.RETRYABLE_STATUS_CODES)).toBe(false);
        expect(isRetryableError(undefined, RETRY_CONFIG.RETRYABLE_STATUS_CODES)).toBe(false);
    });
});
describe('sleep', () => {
    it('should resolve after specified duration', async () => {
        const start = Date.now();
        await sleep(100);
        const end = Date.now();
        const elapsed = end - start;
        // Should be at least 100ms (with some tolerance for execution time)
        expect(elapsed).toBeGreaterThanOrEqual(100);
        expect(elapsed).toBeLessThan(200); // Allow 100ms tolerance
    });
    it('should resolve immediately for zero duration', async () => {
        const start = Date.now();
        await sleep(0);
        const end = Date.now();
        const elapsed = end - start;
        expect(elapsed).toBeLessThan(50);
    });
});
describe('withRetry', () => {
    beforeEach(() => {
        vi.clearAllMocks();
    });
    it('should return result on first attempt if successful', async () => {
        const mockFn = vi.fn().mockResolvedValue('success');
        const result = await withRetry(mockFn);
        expect(result).toBe('success');
        expect(mockFn).toHaveBeenCalledTimes(1);
    });
    it('should retry on retryable errors', async () => {
        const mockFn = vi
            .fn()
            .mockRejectedValueOnce(new BraveApiError(429))
            .mockResolvedValue('success');
        const result = await withRetry(mockFn, { maxRetries: 3, enableJitter: false });
        expect(result).toBe('success');
        expect(mockFn).toHaveBeenCalledTimes(2); // First attempt + 1 retry
    });
    it('should retry multiple times up to maxRetries', async () => {
        const mockFn = vi
            .fn()
            .mockRejectedValueOnce(new BraveApiError(429))
            .mockRejectedValueOnce(new BraveApiError(429))
            .mockRejectedValueOnce(new BraveApiError(429))
            .mockResolvedValue('success');
        const result = await withRetry(mockFn, {
            maxRetries: 5,
            enableJitter: false,
            baseDelay: 100,
            maxDelay: 1000,
        });
        expect(result).toBe('success');
        expect(mockFn).toHaveBeenCalledTimes(4); // First attempt + 3 retries
    }, 10000); // 10 second timeout
    it('should throw error after max retries exhausted', async () => {
        const error = new BraveApiError(429);
        const mockFn = vi.fn().mockRejectedValue(error);
        await expect(withRetry(mockFn, { maxRetries: 2, enableJitter: false })).rejects.toThrow(error);
        expect(mockFn).toHaveBeenCalledTimes(3); // First attempt + 2 retries
    });
    it('should not retry on non-retryable errors (404)', async () => {
        const error = new BraveApiError(404);
        const mockFn = vi.fn().mockRejectedValue(error);
        await expect(withRetry(mockFn, { maxRetries: 5, enableJitter: false })).rejects.toThrow(error);
        expect(mockFn).toHaveBeenCalledTimes(1); // No retries
    });
    it('should not retry on non-retryable errors (401)', async () => {
        const error = new BraveApiError(401);
        const mockFn = vi.fn().mockRejectedValue(error);
        await expect(withRetry(mockFn, { maxRetries: 5, enableJitter: false })).rejects.toThrow(error);
        expect(mockFn).toHaveBeenCalledTimes(1); // No retries
    });
    it('should use exponential backoff between retries', async () => {
        const mockFn = vi
            .fn()
            .mockRejectedValueOnce(new BraveApiError(429))
            .mockRejectedValueOnce(new BraveApiError(429))
            .mockResolvedValue('success');
        const timestamps = [];
        mockFn.mockImplementation(() => {
            timestamps.push(Date.now());
            return Promise.reject(new BraveApiError(429));
        });
        // Override for final success
        mockFn.mockResolvedValueOnce('success');
        await withRetry(mockFn, { maxRetries: 5, baseDelay: 100, maxDelay: 1000, enableJitter: false });
        // Verify that delays increase (exponential backoff)
        // Note: Exact timing is hard to test, so we just verify it completes
        expect(mockFn).toHaveBeenCalledTimes(3);
    });
    it('should apply jitter when enabled', async () => {
        const mockFn = vi
            .fn()
            .mockRejectedValueOnce(new BraveApiError(429))
            .mockResolvedValue('success');
        await withRetry(mockFn, {
            maxRetries: 3,
            baseDelay: 100,
            enableJitter: true,
        });
        expect(mockFn).toHaveBeenCalledTimes(2);
    });
    it('should call onRetry callback before each retry', async () => {
        const mockFn = vi
            .fn()
            .mockRejectedValueOnce(new BraveApiError(429))
            .mockRejectedValueOnce(new BraveApiError(429))
            .mockResolvedValue('success');
        const onRetry = vi.fn();
        await withRetry(mockFn, {
            maxRetries: 5,
            enableJitter: false,
            onRetry,
        });
        expect(onRetry).toHaveBeenCalledTimes(2);
        expect(onRetry).toHaveBeenNthCalledWith(1, 1, expect.any(BraveApiError), 1000);
        expect(onRetry).toHaveBeenNthCalledWith(2, 2, expect.any(BraveApiError), 2000);
    });
    it('should respect custom retryable status codes', async () => {
        const error = new BraveApiError(503);
        const mockFn = vi.fn().mockRejectedValueOnce(error).mockResolvedValue('success');
        const result = await withRetry(mockFn, {
            maxRetries: 3,
            retryableStatusCodes: [503],
            enableJitter: false,
        });
        expect(result).toBe('success');
        expect(mockFn).toHaveBeenCalledTimes(2);
    });
    it('should work with maxRetries = 0 (no retries)', async () => {
        const error = new BraveApiError(429);
        const mockFn = vi.fn().mockRejectedValue(error);
        await expect(withRetry(mockFn, { maxRetries: 0, enableJitter: false })).rejects.toThrow(error);
        expect(mockFn).toHaveBeenCalledTimes(1);
    });
    it('should retry network errors', async () => {
        const networkError = new TypeError('fetch failed');
        const mockFn = vi.fn().mockRejectedValueOnce(networkError).mockResolvedValue('success');
        const result = await withRetry(mockFn, {
            maxRetries: 3,
            enableJitter: false,
        });
        expect(result).toBe('success');
        expect(mockFn).toHaveBeenCalledTimes(2);
    });
});
describe('BraveApiError', () => {
    it('should create error with status code', () => {
        const error = new BraveApiError(429);
        expect(error.statusCode).toBe(429);
        expect(error.name).toBe('BraveApiError');
        expect(error.message).toContain('HTTP 429');
    });
    it('should create error with body', () => {
        const body = { error: { message: 'Rate limited' } };
        const error = new BraveApiError(429, body);
        expect(error.body).toBe(body);
    });
    it('should create error with retryAfter', () => {
        const error = new BraveApiError(429, undefined, 1500);
        expect(error.retryAfter).toBe(1500);
    });
    it('should be instance of Error', () => {
        const error = new BraveApiError(429);
        expect(error instanceof Error).toBe(true);
        expect(error instanceof BraveApiError).toBe(true);
    });
});
